namespace sv_70739db4a5e3418fad795d3af0d0c16e.Services;

public record TaskItem(int Id, string Title, string Assignee, string Priority, DateTime DueDate, string Status);

public interface ITaskService
{
    Task<List<TaskItem>> GetAllTasksAsync();
    Task<TaskItem> CreateTaskAsync(string title, string assignee, string priority, DateTime dueDate);
    Task UpdateTaskStatusAsync(int taskId, string newStatus);
}

@using sv_70739db4a5e3418fad795d3af0d0c16e.Services

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text text-muted small mb-1">@Task.Assignee</p>
        <div class="d-flex justify-content-between align-items-center">
            <span class="badge @PriorityClass">@Task.Priority</span>
            <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        </div>
        <div class="d-flex justify-content-between mt-2">
            @if (CanMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeft">← Move Left</button>
            }
            else
            {
                <span></span>
            }
            @if (CanMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveRight">Move Right →</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@using sv_70739db4a5e3418fad795d3af0d0c16e.Services

<div class="d-flex flex-wrap gap-3 mb-3 p-3 bg-light rounded">
    <div class="badge bg-primary fs-6">Total: @Tasks.Count</div>
    <div class="badge bg-secondary fs-6">To Do: @Tasks.Count(t => t.Status == "To Do")</div>
    <div class="badge bg-info text-dark fs-6">In Progress: @Tasks.Count(t => t.Status == "In Progress")</div>
    <div class="badge bg-success fs-6">Done: @Tasks.Count(t => t.Status == "Done")</div>
    <div class="badge bg-danger fs-6">Overdue: @Tasks.Count(t => t.DueDate < DateTime.Today)</div>
</div>

@code {
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
}

@using sv_70739db4a5e3418fad795d3af0d0c16e.Services

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@Title</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body" style="overflow-y: auto; max-height: 70vh;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          CanMoveLeft="CanMoveLeft"
                          CanMoveRight="CanMoveRight"
                          OnMoveLeft="() => OnMoveTask.InvokeAsync((task.Id, -1))"
                          OnMoveRight="() => OnMoveTask.InvokeAsync((task.Id, 1))" />
            }

            @if (showForm)
            {
                <AddTaskForm Status="@Status"
                             OnSave="HandleTaskSave"
                             OnCancel="() => showForm = false" />
            }
            else
            {
                <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => showForm = true">
                    + Add Task
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string Title { get; set; } = default!;
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<(int TaskId, int Direction)> OnMoveTask { get; set; }
    [Parameter] public EventCallback<(string Status, string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskCreated { get; set; }

    private bool showForm;

    private async Task HandleTaskSave((string Title, string Assignee, string Priority, DateTime DueDate) data)
    {
        await OnTaskCreated.InvokeAsync((Status, data.Title, data.Assignee, data.Priority, data.DueDate));
        showForm = false;
    }
}

@page "/board"
@using sv_70739db4a5e3418fad795d3af0d0c16e.Services
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center p-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="tasks" />
    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        @foreach (var col in columns)
        {
            var colIndex = Array.IndexOf(columns, col);
            <BoardColumn Title="@col"
                         Status="@col"
                         Tasks="GetFilteredTasks(col)"
                         CanMoveLeft="colIndex > 0"
                         CanMoveRight="colIndex < columns.Length - 1"
                         OnMoveTask="args => HandleMoveTask(args.TaskId, col, args.Direction)"
                         OnTaskCreated="HandleTaskCreated" />
        }
    </div>
}

@code {
    private List<TaskItem> tasks = new();
    private string searchText = "";
    private bool loading = true;
    private string? errorMessage;

    private static readonly string[] columns = ["To Do", "In Progress", "Done"];

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        loading = true;
        errorMessage = null;
        try
        {
            tasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var filtered = tasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            filtered = filtered.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return filtered.ToList();
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private async Task HandleMoveTask(int taskId, string currentStatus, int direction)
    {
        var currentIndex = Array.IndexOf(columns, currentStatus);
        var newIndex = currentIndex + direction;
        if (newIndex < 0 || newIndex >= columns.Length) return;

        var newStatus = columns[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = tasks.First(t => t.Id == taskId);
            tasks = tasks.Select(t => t.Id == taskId ? task with { Status = newStatus } : t).ToList();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleTaskCreated((string Status, string Title, string Assignee, string Priority, DateTime DueDate) data)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
            tasks.Add(newTask);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

