@using sv_70739db4a5e3418fad795d3af0d0c16e.Services
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center p-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="tasks" />
    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        @foreach (var col in columns)
        {
            var colIndex = Array.IndexOf(columns, col);
            <BoardColumn Title="@col"
                         Status="@col"
                         Tasks="GetFilteredTasks(col)"
                         CanMoveLeft="colIndex > 0"
                         CanMoveRight="colIndex < columns.Length - 1"
                         OnMoveTask="args => HandleMoveTask(args.TaskId, col, args.Direction)"
                         OnTaskCreated="HandleTaskCreated" />
        }
    </div>
}

@code {
    private List<TaskItem> tasks = new();
    private string searchText = "";
    private bool loading = true;
    private string? errorMessage;

    private static readonly string[] columns = ["To Do", "In Progress", "Done"];

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        loading = true;
        errorMessage = null;
        try
        {
            tasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var filtered = tasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            filtered = filtered.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return filtered.ToList();
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private async Task HandleMoveTask(int taskId, string currentStatus, int direction)
    {
        var currentIndex = Array.IndexOf(columns, currentStatus);
        var newIndex = currentIndex + direction;
        if (newIndex < 0 || newIndex >= columns.Length) return;

        var newStatus = columns[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = tasks.First(t => t.Id == taskId);
            tasks = tasks.Select(t => t.Id == taskId ? task with { Status = newStatus } : t).ToList();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleTaskCreated((string Status, string Title, string Assignee, string Priority, DateTime DueDate) data)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
            tasks.Add(newTask);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}
"}

